    print(f\"=== Period: {row['period']}, Project: {row['project_id']}, Sessions: {row['session_count']} ===\")
    for key in ['rules-skills', 'working-style']:
        section = results.get(key, {})
        print(f\"\n--- {key} ---\")
        if 'rules' in section:
            print('Rules:')
            for r in section['rules']:
                print(f\"  - [{r.get('type','')}] {r.get('rule','')}\")
                if 'rationale' in r:
                    print(f\"    Rationale: {r['rationale']}\")
        if 'narrative' in section:
            print(f\"Narrative: {section['narrative'][:1000]}\")
        # Print all other keys
        for k,v in section.items():
            if k not in ('rules','narrative','section'):
                if isinstance(v, list):
                    print(f\"{k}:\")
                    for item in v:
                        if isinstance(item, dict):
                            print(f\"  - {json.dumps(item, indent=4)[:300]}\")
                        else:
                            print(f\"  - {item}\")
                elif isinstance(v, str):
                    print(f\"{k}: {v[:500]}\")
    print()
